240→// these are constants so that the formats are not recreated every time they are used
241→internal val ISO_OFFSET by lazy {
242→    UtcOffsetFormat.build {
243→        alternativeParsing({ chars("z") }) {
244→            optional("Z") {
245→                offsetHours()
246→                char(':')
247→                offsetMinutesOfHour()
248→                optional {
249→                    char(':')
250→                    offsetSecondsOfMinute()
251→                }
252→            }
253→        }
254→    }
255→}
256→internal val ISO_OFFSET_BASIC by lazy {
257→    UtcOffsetFormat.build {
258→        alternativeParsing({ chars("z") }) {
259→            optional("Z") {
260→                offsetHours()
261→                optional {
262→                    offsetMinutesOfHour()
263→                    optional {
264→                        offsetSecondsOfMinute()
265→                    }
266→                }
267→            }
268→        }
269→    }
270→}
271→
272→internal val FOUR_DIGIT_OFFSET by lazy {
273→    UtcOffsetFormat.build {
274→        offsetHours()
275→        offsetMinutesOfHour()
276→    }
277→}
