 38→    @Test
 39→    fun testInconsistentLocalTime() {
 40→        val formatTime = LocalTime.Format {
 41→            hour(); char(':'); minute();
 42→            chars(" ("); amPmHour(); char(':'); minute(); char(' '); amPmMarker("AM", "PM"); char(')')
 43→        }
 44→        val format = DateTimeComponents.Format { time(formatTime) }
 45→        val time1 = "23:15 (11:15 PM)" // a normal time after noon
 46→        assertDateTimeComponentsEqual(
 47→            DateTimeComponents().apply { hour = 23; hourOfAmPm = 11; minute = 15; amPm = AmPmMarker.PM },
 48→            format.parse(time1)
 49→        )
 50→        assertEquals(LocalTime(23, 15), formatTime.parse(time1))
 51→        val time2 = "23:15 (11:15 AM)" // a time with an inconsistent AM/PM marker
 52→        assertDateTimeComponentsEqual(
 53→            DateTimeComponents().apply { hour = 23; hourOfAmPm = 11; minute = 15; amPm = AmPmMarker.AM },
 54→            format.parse(time2)
 55→        )
 56→        assertFailsWith<IllegalArgumentException> { formatTime.parse(time2) }
 57→        val time3 = "23:15 (10:15 PM)" // a time with an inconsistent number of hours
 58→        assertDateTimeComponentsEqual(
 59→            DateTimeComponents().apply { hour = 23; hourOfAmPm = 10; minute = 15; amPm = AmPmMarker.PM },
 60→            format.parse(time3)
 61→        )
 62→        assertFailsWith<IllegalArgumentException> { formatTime.parse(time3) }
 63→        val time4 = "23:15 (11:16 PM)" // a time with an inconsistently duplicated field
 64→        assertFailsWith<IllegalArgumentException> { format.parse(time4) }
 65→        assertFailsWith<IllegalArgumentException> { formatTime.parse(time4) }
 66→    }
