 80→    @Test
 81→    fun testZonedDateTime() {
 82→        val format = DateTimeComponents.Format {
 83→            dateTime(LocalDateTime.Formats.ISO)
 84→            offset(UtcOffset.Formats.ISO)
 85→            char('[')
 86→            timeZoneId()
 87→            char(']')
 88→        }
 89→        val berlin = "Europe/Berlin"
 90→        val dateTime = LocalDateTime(2008, 6, 3, 11, 5, 30, 123_456_789)
 91→        val offset = UtcOffset(hours = 1)
 92→        val formatted = "2008-06-03T11:05:30.123456789+01:00[Europe/Berlin]"
 93→        assertEquals(formatted, format.format { setDateTime(dateTime); setOffset(offset); timeZoneId = berlin })
 94→        val bag = format.parse("2008-06-03T11:05:30.123456789+01:00[Europe/Berlin]")
 95→        assertEquals(dateTime, bag.toLocalDateTime())
 96→        assertEquals(offset, bag.toUtcOffset())
 97→        assertEquals(berlin, bag.timeZoneId)
 98→        assertFailsWith<DateTimeFormatException> { format.parse("2008-06-03T11:05:30.123456789+01:00[Mars/New_York]") }
 99→        for (zone in TimeZone.availableZoneIds) {
100→            assertEquals(zone, format.parse("2008-06-03T11:05:30.123456789+01:00[$zone]").timeZoneId)
101→        }
102→    }
103→
104→    @Test
105→    fun testTimeZoneGreedyParsing() {
106→        val format = DateTimeComponents.Format { timeZoneId(); chars("X") }
107→        for (zone in TimeZone.availableZoneIds) {
108→            assertEquals(zone, format.parse("${zone}X").timeZoneId)
109→        }
110→    }
