112→    private fun dateTimeComponents(
113→        date: LocalDate? = null,
114→        time: LocalTime? = null,
115→        offset: UtcOffset? = null,
116→        zone: TimeZone? = null
117→    ) = DateTimeComponents().apply {
118→        date?.let { setDate(it) }
119→        time?.let { setTime(it) }
120→        offset?.let { setOffset(it) }
121→        timeZoneId = zone?.id
122→    }
