    try {
        val format = LocalDate.Format {
            year(); char('-'); monthNumber(); char('-'); dayOfMonth()
        }
        format.parse("2020-02-30") // Invalid day for February
    } catch (e: Exception) {
        println("Test 3 - Error message:")
        println(e.message)
        println()
