package kotlinx.datetime.test.format

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

class ErrorMessageTest {

    @Test
    fun testInconsistentTimeWithInputContext() {
        // Test that inconsistent hour/AM-PM errors include the full input
        val formatTime = LocalTime.Format {
            hour(); char(':'); minute();
            chars(" ("); amPmHour(); char(':'); minute(); char(' '); amPmMarker("AM", "PM"); char(')')
        }
        val input = "23:15 (11:15 AM)"
        val error = assertFailsWith<IllegalArgumentException> { formatTime.parse(input) }
        val message = error.message!!
        assertContains(message, "Inconsistent hour and the AM/PM marker")
        assertContains(message, "23")
        assertContains(message, "AM")
        assertTrue(message.contains(input), "Error message should contain the full input: $message")
    }

    @Test
    fun testInvalidDateWithInputContext() {
        // Test that invalid date errors include the full input
        val format = LocalDate.Format {
            year(); char('-'); monthNumber(); char('-'); dayOfMonth()
        }
        val input = "2020-02-30"
        val error = assertFailsWith<IllegalArgumentException> { format.parse(input) }
        val message = error.message!!
        assertTrue(message.contains(input), "Error message should contain the full input: $message")
    }

    @Test
    fun testInvalidMonthNameError() {
        // Test that "one of" (lowercase) is used in error messages
        val format = LocalDate.Format {
            monthName(MonthNames.ENGLISH_ABBREVIATED)
            char(' ')
            dayOfMonth()
        }
        val input = "Xyz 15"
        val error = assertFailsWith<IllegalArgumentException> { format.parse(input) }
        val message = error.message!!
        assertContains(message, "one of")
        assertTrue(message.contains(input), "Error message should contain the full input: $message")
    }

    @Test
    fun testInvalidDayOfWeekNameError() {
        // Test that "one of" (lowercase) is used in error messages for day of week
        val format = LocalDate.Format {
            dayOfWeek(DayOfWeekNames.ENGLISH_ABBREVIATED)
            char(' ')
            monthName(MonthNames.ENGLISH_ABBREVIATED)
            char(' ')
            dayOfMonth()
        }
        val input = "Xyz Jan 15"
        val error = assertFailsWith<IllegalArgumentException> { format.parse(input) }
        val message = error.message!!
        assertContains(message, "one of")
        assertTrue(message.contains(input), "Error message should contain the full input: $message")
    }

    @Test
    fun testInvalidTimeWithInputContext() {
        // Test that out-of-bounds time values include the full input
        val format = LocalTime.Formats.ISO
        val input = "40:36"
        val error = assertFailsWith<IllegalArgumentException> { format.parse(input) }
        val message = error.message!!
        assertTrue(message.contains(input), "Error message should contain the full input: $message")
    }

    @Test
    fun testInvalidUtcOffsetWithInputContext() {
        // Test that invalid UTC offset errors include the full input
        val format = UtcOffset.Formats.ISO
        val input = "+99:00"
        val error = assertFailsWith<IllegalArgumentException> { format.parse(input) }
        val message = error.message!!
        assertTrue(message.contains(input), "Error message should contain the full input: $message")
    }

    @Test
    fun testAmPmMarkerError() {
        // Test that AM/PM marker errors use lowercase "one of"
        val format = LocalTime.Format {
            amPmHour()
            char(':')
            minute()
            char(' ')
            amPmMarker("AM", "PM")
        }
        val input = "11:15 XM"
        val error = assertFailsWith<IllegalArgumentException> { format.parse(input) }
        val message = error.message!!
        assertContains(message, "one of")
        assertTrue(message.contains(input), "Error message should contain the full input: $message")
    }
}
"}

